mapper.select:
SELECT COUNT(1) FROM student_answer_record

    
        AND paper_id = #{paperId}
    
    
        AND student_id = #{studentId}
    
    
        AND review_status = #{reviewStatus}

SELECT sar.*, q.question_type as questionType, q.stem, q.options, q.answer as correctAnswer, q.analysis
FROM student_answer_record sar
LEFT JOIN question q ON sar.question_id = q.id

    
        AND sar.paper_id = #{paperId}
    
    
        AND sar.student_id = #{studentId}
    
    
        AND sar.review_status = #{reviewStatus}
    

ORDER BY sar.create_time DESC
LIMIT #{pageSize} OFFSET #{offset}
